// @mui
import { styled } from "@mui/material/styles";
import { useState, useEffect } from "react";

// components
import Page from "../../components/Page";
// sections
import { Box, IconButton, InputAdornment, Typography } from "@mui/material";
import TextField from "../../components/core/LabeledInput";
import { borderRadius } from "@mui/system";
import { IconButtonAnimate, varFade } from "../../components/animate";
import Iconify from "../../components/Iconify";
import Footer from "../../components/onboarding/footer";
import { useLocation, useNavigate } from "react-router";
import AddCircleIcon from "@mui/icons-material/AddCircle";
import AccountCircleIcon from "@mui/icons-material/AccountCircle";
import axios from "../../utils/axios";
import api from "../../utils/api";
import Input from "src/components/Labs/Cropper";
import { updateFeedback } from "../../redux/actions/feedback";
import { useDispatch } from "react-redux";
import { updateOnboarding } from "../../redux/actions/Onboarding";
import { useSelector } from "react-redux";
import { initProfile } from "src/redux/actions/Profile";
import { handleuploadImage } from "src/utils/uploader";
// ----------------------------------------------------------------------
import Header from "../../components/onboarding/header";
const RootStyle = styled("div")(() => ({
  display: "flex",
  flexDirection: "column",
  flex: 1,
  flexGrow: 1,
  background: "#fff",
  height: "100vh",
}));

const BoxStyle = styled(Box)(() => ({
  position: "relative",
}));

const InsideBoxStyle = styled(Box)(() => ({
  position: "absolute",
  width: "100%",
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
  flexDirection: "column",
  paddingTop: 52,
  paddingBottom: 24,
  zIndex: 100,
  top: 0,
}));

// ----------------------------------------------------------------------

export default function ProfilePic({mode}) {
  const navigate = useNavigate();
const {state}=useLocation()
  const Onboarding = useSelector((s) => s.Onboarding);
  const [profilePic, setPic] = useState(Onboarding.profilePic);
  const [about, setAbout] = useState(Onboarding.about);
  const dispatch = useDispatch();

  const uploadImage = (e) => {
    dispatch(updateFeedback({ loading: true }));

    handleuploadImage(e).then(
      (res) => {
        setPic(res.data.Location);
        dispatch(updateFeedback({ loading: false }));
      },
      (rej) => {
        if (rej == "size")
          return dispatch(
            updateFeedback({
              loading: false,
              snackbar: true,
              message: "Image size should be less than 5 mb",
              severity: "warning",
            })
          );
        else
          return dispatch(
            updateFeedback({
              loading: false,
              snackbar: true,
              message: "Error in uploading image please try again later",
              severity: "warning",
            })
          );
      }
    );
  };

  useEffect(() => {
    dispatch(updateOnboarding({ profilePic: profilePic, bio: about }));
  }, [profilePic, about]);

  const handleNext = () => {
    axios
      .post(`${api.protocol}${api.baseUrl}${api.userSignup}`, {
        ...Onboarding,
        type:mode=="client"?"Athlete":"Instructor"
      })
      .then((response) => {
        dispatch(
          updateFeedback({
            loading: false,
            sAnimate: true,
            message: "Figgs account created succesfully",
            severity: "success",
          })
        );
        dispatch(updateOnboarding({ token: response.data.token }));
        localStorage.setItem("token", response.data.token);
        axios.defaults.headers.common["Authorization"] = response.data.token;
        dispatch(
          initProfile({
            ...response.data.userData,
            password: "",
            ...response.data,
          })
        );
        if(state.redirect){
          navigate(state.redirect)
        }
        else
        navigate("/",{state});
      })
      .catch((error) => {
        return dispatch(
          updateFeedback({
            loading: false,
            snackbar: true,
            message: "Unexpected error! Please try again",
            severity: "error",
          })
        );
      });
  };

  return (
    <Page title="The starting point for your next fitness gig">
      <Input
        type="file"
        onChange={uploadImage}
        id="profile-img"
        aspect={1}
        style={{ display: "none" }}
      />
      <RootStyle>
        <Header title={"Create new account"} onClose={() => navigate("/",{state})} />
        <Box
          display={"flex"}
          height={"100%"}
          flexDirection={"column"}
          alignItems={"center"}
          flexGrow={"1"}
          px={2}
        >
          <Typography variant="h2" sx={{ my: 6, mb: 2 }}>
            Your Profile
          </Typography>

          <Box width={"100%"} display="flex" justifyContent={"center"}>
            <Box
              style={{
                borderRadius: "50%",
                position: "relative",
                height: 120,
                width: 120,
                backgroundImage: `url(${
                  profilePic ? profilePic : AccountCircleIcon
                })`,
                backgroundSize: "cover",
              }}
              sx={{ mb: 4 }}
              onClick={() => document.getElementById("profile-img").click()}
            >
              {!profilePic && (
                <AccountCircleIcon sx={{ fontSize: 120, color: "#E1E7F0" }} />
              )}
              <IconButton
                sx={{ position: "absolute", bottom: 5, right: -5 }}
              >
                <AddCircleIcon sx={{ fontSize: 40 }} color={"primary"} />
              </IconButton>
            </Box>
          </Box>

          <TextField
            fullWidth
            placeholder=""
            multiline
            clabel={mode=="client"?"Goals":"About yourself"}
            rows={4}
            onChange={(e) => setAbout(e.target.value)}
          />
        </Box>
        <Footer next nextClick={handleNext} />
      </RootStyle>
    </Page>
  );
}
